/**
 * @param {number} n
 * @param {number[][]} edges
 * @param {number} k
 * @return {number}
 */
function solve(n, edges, k) {
    // Sort edges by weight in ascending order
    edges.sort((a, b) => a[2] - b[2]);

    // Initialize Union-Find structure
    const uf = new UnionFind(n);

    // Track the number of connected components
    let components = n;

    // Track the maximum edge weight in each component
    const maxEdge = new Array(n).fill(0);

    // Process edges in order of increasing weight
    for (const [u, v, w] of edges) {
        // If the nodes are in different components, merge them
        if (uf.find(u) !== uf.find(v)) {
            uf.union(u, v);
            components--;

            // Update the max edge weight for the new component
            maxEdge[uf.find(u)] = Math.max(maxEdge[uf.find(u)], w);
        }
    }

    // If k is 1, the answer is the maximum edge weight in the entire graph
    if (k === 1) {
        return Math.max(...maxEdge);
    }

    // Otherwise, the answer is the (k-th) maximum edge weight in the components
    // We need to find the k-th maximum edge weight in the maxEdge array
    // Sort the maxEdge array in descending order and take the (k-1)-th element
    const sortedMaxEdge = [...maxEdge].sort((a, b) => b - a);
    return sortedMaxEdge[k - 1];
}

// Union-Find data structure
class UnionFind {
    constructor(n) {
        this.parent = Array(n).fill(0).map((_, i) => i);
        this.rank = Array(n).fill(0);
    }

    find(x) {
        if (this.parent[x] !== x) {
            this.parent[x] = this.find(this.parent[x]);
        }
        return this.parent[x];
    }

    union(x, y) {
        const xRoot = this.find(x);
        const yRoot = this.find(y);

        if (xRoot === yRoot) {
            return false;
        }

        if (this.rank[xRoot] < this.rank[yRoot]) {
            this.parent[xRoot] = yRoot;
        } else {
            this.parent[yRoot] = xRoot;
            if (this.rank[xRoot] === this.rank[yRoot]) {
                this.rank[xRoot]++;
            }
        }
        return true;
    }
}

